import json
from typing import List, Dict, Any

# Pré-définir pour éviter les problèmes Shuffle
true = True
false = False
null = None

def extract_opencti_indicators(raw_results: Any) -> List[Dict[str, Any]]:
    """
    Extrait les indicateurs OpenCTI positifs NON RÉVOQUÉS avec les champs utiles.
    """
    # Extraction de la liste réelle des résultats
    results = []
    if isinstance(raw_results, list):
        results = raw_results
    elif isinstance(raw_results, dict):
        for key in raw_results:
            if isinstance(raw_results[key], list):
                results = raw_results[key]
                break

    opencti_positive = []
    for item in results:
        if not isinstance(item, dict) or not item.get("success", False):
            continue
        body = item.get("body", {})
        if not isinstance(body, dict):
            continue
        data = body.get("data", {})
        if not isinstance(data, dict):
            continue
        indicators = data.get("indicators", {})
        if not isinstance(indicators, dict):
            continue
        edges = indicators.get("edges", [])
        if not edges:
            continue
        for edge in edges:
            node = edge.get("node", {})
            if not isinstance(node, dict):
                continue
            # Extraction des labels
            labels = []
            object_label = node.get("objectLabel", [])
            if isinstance(object_label, list):
                for lbl in object_label:
                    if isinstance(lbl, dict):
                        labels.append(lbl.get("value", ""))
            # Créé par
            created_by = "Unknown"
            created_by_obj = node.get("createdBy", {})
            if isinstance(created_by_obj, dict):
                created_by = created_by_obj.get("name", "Unknown")
            # Observable = name
            observable = node.get("name", "unknown")
            entry = {
                "observable": observable,
                "opencti_score": node.get("x_opencti_score", 0),
                "valid_from": node.get("valid_from", ""),
                "valid_until": node.get("valid_until", ""),
                "revoked": node.get("revoked", false),
                "object_labels": labels
            }
            opencti_positive.append(entry)
    return opencti_positive


# ==========================================
# EXÉCUTION DANS SHUFFLE
# ==========================================
raw_input = $merge_searches # Remplace par ta variable réelle

try:
    if isinstance(raw_input, str):
        try:
            raw_input = json.loads(raw_input)
        except:
            raw_input = []
    positive_indicators = extract_opencti_indicators(raw_input)
    output = {
        "opencti_positive_iocs": positive_indicators,
        "total_opencti_received": len(raw_input) if isinstance(raw_input, list) else 0,
        "total_opencti_found": len(positive_indicators)
    }
    print(json.dumps(output, indent=2, ensure_ascii=False))
except Exception as e:
    error_output = {
        "opencti_iocs": [],
        "total_opencti_received": 0,
        "total_opencti_found": 0,
        "error": str(e)
    }
    print(json.dumps(error_output, indent=2, ensure_ascii=False))
